32	  provider?: {
33	    id?: string;
34	    label: string;
35	    docsPath: string;
36	    aliases?: string[];
37	    envVars?: string[];
38	    auth?: SingleProviderPluginApiKeyAuthOptions[];
39	    catalog: SingleProviderPluginCatalogOptions;
40	  } & Omit<
41	    ProviderPlugin,
42	    "id" | "label" | "docsPath" | "aliases" | "envVars" | "auth" | "catalog"
43	  >;
44	  register?: (api: OpenClawPluginApi) => void;
45	};
