47	function resolveWizardSetup(params: {
48	  providerId: string;
49	  providerLabel: string;
50	  auth: SingleProviderPluginApiKeyAuthOptions;
51	}): ProviderPluginWizardSetup | undefined {
52	  if (params.auth.wizard === false) {
53	    return undefined;
54	  }
55	  const wizard = params.auth.wizard ?? {};
56	  const methodId = params.auth.methodId.trim();
57	  return {
58	    choiceId: wizard.choiceId ?? `${params.providerId}-${methodId}`,
59	    choiceLabel: wizard.choiceLabel ?? params.auth.label,
60	    ...(wizard.choiceHint ? { choiceHint: wizard.choiceHint } : {}),
61	    groupId: wizard.groupId ?? params.providerId,
62	    groupLabel: wizard.groupLabel ?? params.providerLabel,
63	    ...((wizard.groupHint ?? params.auth.hint)
64	      ? { groupHint: wizard.groupHint ?? params.auth.hint }
65	      : {}),
66	    methodId,
67	    ...(wizard.onboardingScopes ? { onboardingScopes: wizard.onboardingScopes } : {}),
68	    ...(wizard.modelAllowlist ? { modelAllowlist: wizard.modelAllowlist } : {}),
69	  };
70	}
71	
72	function resolveEnvVars(params: {
73	  envVars?: string[];
74	  auth?: SingleProviderPluginApiKeyAuthOptions[];
75	}): string[] | undefined {
76	  const combined = [
77	    ...(params.envVars ?? []),
78	    ...(params.auth ?? []).map((entry) => entry.envVar).filter(Boolean),
79	  ]
80	    .map((value) => value.trim())
81	    .filter(Boolean);
82	  return combined.length > 0 ? [...new Set(combined)] : undefined;
83	}
84	
85	export function defineSingleProviderPluginEntry(options: SingleProviderPluginOptions) {
86	  return definePluginEntry({
87	    id: options.id,
88	    name: options.name,
89	    description: options.description,
90	    ...(options.kind ? { kind: options.kind } : {}),
91	    ...(options.configSchema ? { configSchema: options.configSchema } : {}),
92	    register(api) {
93	      const provider = options.provider;
94	      if (provider) {
95	        const providerId = provider.id ?? options.id;
96	        const envVars = resolveEnvVars({
97	          envVars: provider.envVars,
98	          auth: provider.auth,
99	        });
100	        const auth = (provider.auth ?? []).map((entry) => {
101	          const { wizard: _wizard, ...authParams } = entry;
102	          const wizard = resolveWizardSetup({
103	            providerId,
104	            providerLabel: provider.label,
105	            auth: entry,
106	          });
107	          return createProviderApiKeyAuthMethod({
108	            ...authParams,
109	            providerId,
110	            expectedProviders: entry.expectedProviders ?? [providerId],
111	            ...(wizard ? { wizard } : {}),
112	          });
113	        });
114	        api.registerProvider({
115	          id: providerId,
116	          label: provider.label,
117	          docsPath: provider.docsPath,
118	          ...(provider.aliases ? { aliases: provider.aliases } : {}),
119	          ...(envVars ? { envVars } : {}),
120	          auth,
121	          catalog: {
122	            order: "simple",
123	            run: (ctx) =>
124	              buildSingleProviderApiKeyCatalog({
125	                ctx,
126	                providerId,
127	                buildProvider: provider.catalog.buildProvider,
128	                ...(provider.catalog.allowExplicitBaseUrl ? { allowExplicitBaseUrl: true } : {}),
129	              }),
130	          },
131	          ...Object.fromEntries(
132	            Object.entries(provider).filter(
133	              ([key]) =>
134	                !["id", "label", "docsPath", "aliases", "envVars", "auth", "catalog"].includes(key),
135	            ),
136	          ),
137	        });
138	      }
139	      options.register?.(api);
140	    },
141	  });
142	}
