import { resolvePulseboardAccount } from "./accounts.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard server to verify connectivity.
 *
 * The PulseBoard platform is fictional; this stubs the HTTP health check that
 * a real implementation would perform against `serverUrl/api/v1/health`.
 */
export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseboardProbe = {
    ok: false,
    serverUrl: account.serverUrl,
    username: account.username,
  };

  if (!account.configured) {
    return {
      ...base,
      error: "missing serverUrl, username, or apiToken",
    };
  }

  const started = Date.now();
  try {
    // Stubbed health check — a real implementation would call:
    //   GET ${account.serverUrl}/api/v1/health
    // with Authorization: Bearer ${account.apiToken}
    const url = `${account.serverUrl}/api/v1/health`;
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), opts?.timeoutMs ?? 8000);
    try {
      const res = await fetch(url, {
        method: "GET",
        headers: { Authorization: `Bearer ${account.apiToken}` },
        signal: controller.signal,
      });
      clearTimeout(timer);
      if (!res.ok) {
        return {
          ...base,
          error: `HTTP ${res.status} ${res.statusText}`,
        };
      }
    } finally {
      clearTimeout(timer);
    }
    const elapsed = Date.now() - started;
    return {
      ...base,
      ok: true,
      latencyMs: elapsed,
    };
  } catch (err) {
    return {
      ...base,
      error: formatError(err),
    };
  }
}

