import { resolvePulseboardAccount } from "./accounts.js";
import { normalizePulseboardMessagingTarget } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
  target?: string;
};

function recordOutboundActivity(accountId: string): void {
  try {
    getPulseboardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string, opts?: SendPulseboardOptions): string {
  const fromArg = normalizePulseboardMessagingTarget(to);
  if (fromArg) {
    return fromArg;
  }
  const fromOpt = normalizePulseboardMessagingTarget(opts?.target ?? "");
  if (fromOpt) {
    return fromOpt;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

/**
 * Send a message to a PulseBoard board or user.
 *
 * The PulseBoard platform is fictional; this stubs the HTTP POST that a real
 * implementation would send to `serverUrl/api/v1/messages`.
 */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl, username, and apiToken in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to, opts);
  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();

  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Stubbed HTTP call — a real implementation would POST to:
  //   ${account.serverUrl}/api/v1/messages
  // Body: { target, text: payload, username: account.username }
  // Headers: { Authorization: `Bearer ${account.apiToken}` }
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;

  recordOutboundActivity(account.accountId);

  return { messageId, target };
}

