     export type PulseboardAccountConfig = { name?: string; enabled?: boolean; serverUrl?: string; apiToken?: string; username?: string; boards?: string[]; dmPolicy?: DmPolicy; allowFrom?: Array<string | number>; defaultTo?: string; groupPolicy?: GroupPolicy; groupAllowFrom?: Array<string | number>; groups?: Record<string, PulseboardGroupConfig>; historyLimit?: number; textChunkLimit?: number; };
     export type PulseboardConfig = PulseboardAccountConfig & { accounts?: Record<string, PulseboardAccountConfig>; defaultAccount?: string; };
     export type CoreConfig = OpenClawConfig & { channels?: OpenClawConfig["channels"] & { pulseboard?: PulseboardConfig; }; };
     export type PulseboardInboundMessage = { messageId: string; target: string; senderUsername: string; text: string; timestamp: number; isGroup: boolean; };
     export type PulseboardProbe = BaseProbeResult<string> & { serverUrl: string; username: string; latencyMs?: number; };
     ```

   - **`extensions/pulseboard/src/config-schema.ts`** — Zod schema using `openclaw/plugin-sdk/channel-config-schema` and `openclaw/plugin-sdk/zod`; exports `PulseboardChannelConfigSchema = buildChannelConfigSchema(PulseboardConfigSchema)`

   - **`extensions/pulseboard/src/normalize.ts`** — Target normalization:
     ```ts
     export function isBoardTarget(target: string): boolean { return target.startsWith("!"); }
     export function normalizePulseboardMessagingTarget(raw: string): string | undefined { ... }
     export function looksLikePulseboardTargetId(raw: string): boolean { ... }
